prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?lang ?modelName ?modelId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:normalizedId ?modelId .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?defs bboExt:typeLanguage ?lang . }
  OPTIONAL { ?defs bboExt:expressionLanguage ?exprLang . }
  BIND(COALESCE(?lang, ?exprLang) AS ?lang)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?finalLang ?modelName ?modelId WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:normalizedId ?modelId .

  ?defs tai:belongsTo ?model .

  OPTIONAL { ?defs bboExt:typeLanguage ?typeLang . }
  OPTIONAL { ?defs bboExt:expressionLanguage ?exprLang . }

  BIND(COALESCE(?typeLang, ?exprLang) AS ?finalLang)
}
ORDER BY ?finalLang ?modelName
LIMIT 25
